+			output: "done",
+			sessionId: "session-1",
+		});
+
+		expect(result.stumbles).toBe(1);
+		expect(result.sessionEndData).toEqual({
+			session_id: "session-1",
+			success: true,
+			stumbles: 1,
+			turns: 2,
+			timed_out: false,
+			output: "done",
+		});
+		expect(result.agentResult).toEqual({
+			output: "done",
+			success: true,
+			stumbles: 1,
+			turns: 2,
+			timed_out: false,
+		});
+	});
+
+	test("increments stumbles on timeout and exposes timed_out fields", () => {
+		const result = finalizeRunLoopResult({
+			turns: 3,
+			stumbles: 2,
+			maxTurns: 10,
+			timeoutMs: 50,
+			elapsedMs: 75,
+			interrupted: false,
+			output: "partial",
+			sessionId: "session-2",
+		});
